const settings = $('Load Global Settings').first()?.json ?? {};
const request = $('Preview Member Template Email Webhook').first()?.json ?? $input.first()?.json ?? {};
const query = request.query ?? request;
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const truthy = (value) => ['1', 'true', 'yes', 'y', 'on'].includes(clean(value).toLowerCase());
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const member = clean(query.member);
const membership = clean(query.membership);
const email = clean(query.email);
const templateKey = clean(query.template_key);
const returnUrl = clean(query.return_url) || `${n8nBaseUrl}/webhook/member-search-detail?member=${encodeURIComponent(member)}&membership=${encodeURIComponent(membership)}&email=${encodeURIComponent(email)}`;
const rawMemberId = Number.parseInt(clean(query.member_id), 10);
const defaultDeliveryMode = clean(settings.default_delivery_mode).toLowerCase() === 'production' ? 'production' : 'test';
const forceTest = truthy(query.test_mode) || clean(query.delivery_mode).toLowerCase() === 'test' || defaultDeliveryMode !== 'production';
const deliveryMode = forceTest ? 'test' : 'production';
const errorMessage = !templateKey ? 'template_key is required' : (!member && !Number.isInteger(rawMemberId) ? 'member_id or member is required' : '');
return [{ json: { member_id: Number.isInteger(rawMemberId) ? rawMemberId : null, member, membership, email, template_key: templateKey, signature_template_key: settings.email_signature_template_key || 'signature', sender_name: settings.email_sender_name || 'Steve Short', reply_to: settings.email_reply_to || 'members.avondaleltc@gmail.com', delivery_mode: deliveryMode, test_recipient: clean(settings.default_test_recipient) || 'steve.short@gmail.com', return_url: returnUrl, n8n_base_url: n8nBaseUrl, error_message: errorMessage } }];

const input = $input.first().json ?? {};
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sqlInteger = (value) => Number.isInteger(value) ? String(value) : 'NULL';
const memberSql = sqlLiteral(input.member);
const membershipSql = sqlLiteral(input.membership);
const emailSql = sqlLiteral(input.email);
const templateSql = sqlLiteral(input.template_key);
const signatureTemplateSql = sqlLiteral(input.signature_template_key || 'signature');
const memberIdSql = sqlInteger(input.member_id);
const sql = `
WITH base_member AS (
  SELECT rm.id AS raw_member_id, trim(concat_ws(' ', rm."First name", rm."Last name")) AS member_name, rm."First name" AS first_name, rm."Last name" AS last_name, NULLIF(trim(rm."Email address"), '') AS member_email, NULLIF(trim(rm."Venue ID"), '') AS venue_id, rm."Membership" AS membership, NULLIF(trim(rm."Status"), '') AS member_status, NULLIF(trim(rm."Payment"), '') AS payment_status, NULLIF(trim(rm."Start Date"), '') AS start_date, NULLIF(trim(rm."Expiry Date"), '') AS expiry_date, rm."Paid" AS paid_total, NULLIF(trim(rm."Address 1"), '') AS address_1, NULLIF(trim(rm."Postcode"), '') AS postcode
  FROM public.raw_members rm
  WHERE COALESCE(rm.is_current, true) = true
    AND ((${memberIdSql} IS NOT NULL AND rm.id = ${memberIdSql}) OR (${memberIdSql} IS NULL AND trim(concat_ws(' ', rm."First name", rm."Last name")) = ${memberSql} AND (${membershipSql} = '' OR rm."Membership" = ${membershipSql}) AND (${emailSql} = '' OR public.normalize_match_email(rm."Email address") = public.normalize_match_email(${emailSql}))))
  ORDER BY CASE WHEN (${membershipSql} <> '' AND rm."Membership" = ${membershipSql}) THEN 0 ELSE 1 END, rm.id
  LIMIT 1
), member_identity AS (
  SELECT COALESCE((SELECT raw_member_id FROM base_member), ${memberIdSql}) AS raw_member_id, COALESCE((SELECT member_name FROM base_member), ${memberSql}) AS member_name, COALESCE((SELECT first_name FROM base_member), split_part(${memberSql}, ' ', 1)) AS first_name, COALESCE((SELECT last_name FROM base_member), NULLIF(regexp_replace(${memberSql}, '^\\S+\\s*', ''), '')) AS last_name, COALESCE((SELECT member_email FROM base_member), NULLIF(${emailSql}, '')) AS member_email, COALESCE((SELECT membership FROM base_member), NULLIF(${membershipSql}, '')) AS membership, COALESCE((SELECT member_status FROM base_member), NULL) AS member_status, COALESCE((SELECT payment_status FROM base_member), NULL) AS payment_status, COALESCE((SELECT start_date FROM base_member), NULL) AS start_date, COALESCE((SELECT expiry_date FROM base_member), NULL) AS expiry_date, COALESCE((SELECT paid_total FROM base_member), NULL::numeric) AS paid_total, COALESCE((SELECT address_1 FROM base_member), NULL) AS address_1, COALESCE((SELECT postcode FROM base_member), NULL) AS postcode
), best_contact AS (
  SELECT bc.*
  FROM member_identity mi
  LEFT JOIN LATERAL public.resolve_best_contact_row(mi.member_name, COALESCE(NULLIF(${emailSql}, ''), mi.member_email), NULLIF(regexp_replace(mi.member_name, '^\\S+\\s*', ''), ''), EXISTS (SELECT 1 FROM public.raw_members rmf WHERE COALESCE(rmf.is_current, true) = true AND trim(concat_ws(' ', rmf."First name", rmf."Last name")) = mi.member_name AND rmf."Membership" ILIKE '%Family%')) bc ON TRUE
), main_contact_candidates AS (
  SELECT trim(concat_ws(' ', mc."First name", mc."Last name")) AS main_contact_name, NULLIF(trim(mc."Email address"), '') AS main_contact_email, NULLIF(trim(mc."Address 1"), '') AS main_contact_address_1, NULLIF(trim(mc."Town"), '') AS main_contact_town, NULLIF(trim(mc."Postcode"), '') AS main_contact_postcode, row_number() OVER (ORDER BY CASE WHEN NULLIF(trim(mc."Email address"), '') IS NOT NULL THEN 0 ELSE 1 END, CASE WHEN mi.last_name IS NOT NULL AND public.normalize_match_text(mc."Last name") = public.normalize_match_text(mi.last_name) THEN 0 ELSE 1 END, CASE WHEN mi.postcode IS NOT NULL AND public.normalize_match_text(mc."Postcode") = public.normalize_match_text(mi.postcode) THEN 0 ELSE 1 END, mc.id DESC) AS candidate_rank
  FROM member_identity mi
  JOIN public.vw_raw_members_main_contacts_current mc
    ON trim(concat_ws(' ', mc."First name", mc."Last name")) <> mi.member_name
   AND COALESCE(mc."Membership", '') = COALESCE(mi.membership, '')
   AND COALESCE(mc."Status", '') = COALESCE(mi.member_status, '')
   AND COALESCE(mc."Payment", '') = COALESCE(mi.payment_status, '')
   AND COALESCE(mc."Start Date", '') = COALESCE(mi.start_date, '')
   AND COALESCE(mc."Expiry Date", '') = COALESCE(mi.expiry_date, '')
   AND COALESCE(mc."Paid", -1::numeric) = COALESCE(mi.paid_total, -1::numeric)
   AND ((mi.last_name IS NOT NULL AND public.normalize_match_text(mc."Last name") = public.normalize_match_text(mi.last_name)) OR (mi.postcode IS NOT NULL AND public.normalize_match_text(mc."Postcode") = public.normalize_match_text(mi.postcode)) OR (mi.address_1 IS NOT NULL AND public.normalize_match_text(mc."Address 1") = public.normalize_match_text(mi.address_1)))
), main_contact AS (
  SELECT COALESCE(NULLIF(TRIM(bcm.email_address), ''), mcc.main_contact_email) AS email_address, COALESCE(NULLIF(TRIM(bcm.address_1), ''), mcc.main_contact_address_1) AS address_1, COALESCE(NULLIF(TRIM(bcm.town), ''), mcc.main_contact_town) AS town, COALESCE(NULLIF(TRIM(bcm.postcode), ''), mcc.main_contact_postcode) AS postcode, mcc.main_contact_name
  FROM main_contact_candidates mcc
  LEFT JOIN LATERAL public.resolve_best_contact_row(mcc.main_contact_name, mcc.main_contact_email, NULLIF(regexp_replace(mcc.main_contact_name, '^\\S+\\s*', ''), ''), false) bcm ON TRUE
  WHERE mcc.candidate_rank = 1
), main_template AS (
  SELECT template_key, template_name, subject_template, text_template, html_template
  FROM public.email_templates
  WHERE template_key = ${templateSql}
    AND is_active = true
    AND template_type = 0
  ORDER BY id DESC
  LIMIT 1
), signature_template AS (
  SELECT template_key, template_name, subject_template, text_template, html_template
  FROM public.email_templates
  WHERE template_key = ${signatureTemplateSql}
    AND is_active = true
    AND template_type = 2
  ORDER BY id DESC
  LIMIT 1
)
SELECT mi.member_name, mi.first_name, mi.last_name, mi.membership, COALESCE(NULLIF(${emailSql}, ''), NULLIF(TRIM(mc.email_address), ''), NULLIF(TRIM(bc.email_address), ''), NULLIF(TRIM(mi.member_email), '')) AS to_email, COALESCE(NULLIF(TRIM(mc.address_1), ''), NULLIF(TRIM(bc.address_1), ''), '') AS address_1, COALESCE(NULLIF(TRIM(mc.town), ''), NULLIF(TRIM(bc.town), ''), '') AS town, COALESCE(NULLIF(TRIM(mc.postcode), ''), NULLIF(TRIM(bc.postcode), ''), '') AS postcode, (SELECT template_key FROM main_template) AS template_key, (SELECT template_name FROM main_template) AS template_name, (SELECT subject_template FROM main_template) AS subject_template, (SELECT text_template FROM main_template) AS text_template, (SELECT html_template FROM main_template) AS html_template, (SELECT template_key FROM signature_template) AS signature_template_key, (SELECT text_template FROM signature_template) AS signature_text_template, (SELECT html_template FROM signature_template) AS signature_html_template, CASE WHEN COALESCE(mi.member_name, '') = '' THEN 'Member is required' WHEN COALESCE(COALESCE(NULLIF(${emailSql}, ''), NULLIF(TRIM(mc.email_address), ''), NULLIF(TRIM(bc.email_address), ''), NULLIF(TRIM(mi.member_email), '')), '') = '' THEN 'No email address found for ' || mi.member_name WHEN NOT EXISTS (SELECT 1 FROM main_template) THEN 'Email template ' || ${templateSql} || ' was not found or is not a message template' ELSE NULL END AS error_message FROM member_identity mi LEFT JOIN best_contact bc ON TRUE LEFT JOIN main_contact mc ON TRUE;`;
return [{ json: { ...input, sql } }];

const input = $('Resolve Preview Request').first().json ?? {};
const errorRow = $('Load Preview Context').first()?.json ?? {};
const message = errorRow.error_message || input.error_message || 'Unable to prepare email preview.';
const returnUrl = input.return_url || '#';
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Email Preview Unavailable</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}h1{margin:0 0 10px;font-size:30px}p{color:#6b7785;line-height:1.5}.message{margin:18px 0;padding:14px 16px;border-radius:14px;background:#fdecec;color:#b93a3a;font-weight:700}.actions{margin-top:22px;display:flex;gap:12px;flex-wrap:wrap}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Email Preview Unavailable</h1><p>The member-detail email panel could not build a preview for this request.</p><div class="message">${escapeHtml(message)}</div><div class="actions"><a class="button" href="${escapeHtml(returnUrl)}">Back to Member Detail</a></div></div></body></html>`;
return [{ json: { html } }];

const input = $('Resolve Preview Request').first().json ?? {};
const context = $('Load Preview Context').first()?.json ?? {};
const tokenMap = {
  '{{$json.first_name}}': context.first_name ?? '',
  '{{$json.last_name}}': context.last_name ?? '',
  '{{$json.email_address}}': context.to_email ?? '',
  '{{$json.address_1}}': context.address_1 ?? '',
  '{{$json.town}}': context.town ?? '',
  '{{$json.postcode}}': context.postcode ?? '',
  '{{$json.membership}}': context.membership ?? '',
  '{{$json.contact.first_name}}': context.first_name ?? '',
  '{{$json.contact.last_name}}': context.last_name ?? '',
  '{{$json.contact.email_address}}': context.to_email ?? '',
  '{{$json.contact.address_1}}': context.address_1 ?? '',
  '{{$json.contact.town}}': context.town ?? '',
  '{{$json.contact.postcode}}': context.postcode ?? '',
  '{{$json.member.first_name}}': context.first_name ?? '',
  '{{$json.member.last_name}}': context.last_name ?? '',
  '{{$json.member.email_address}}': context.to_email ?? '',
  '{{$json.member.membership}}': context.membership ?? '',
  '{{first_name}}': context.first_name ?? '',
  '{{last_name}}': context.last_name ?? '',
  '{{email_address}}': context.to_email ?? '',
  '{{address_1}}': context.address_1 ?? '',
  '{{town}}': context.town ?? '',
  '{{postcode}}': context.postcode ?? '',
  '{{membership}}': context.membership ?? '',
  '<first name>': context.first_name ?? '',
  '<last name>': context.last_name ?? '',
  '<email address>': context.to_email ?? '',
  '{contact.first_name}': context.first_name ?? '',
  '{contact.last_name}': context.last_name ?? '',
  '{contact.email_address}': context.to_email ?? '',
  '{contact.address_1}': context.address_1 ?? '',
  '{contact.town}': context.town ?? '',
  '{contact.postcode}': context.postcode ?? '',
  '{member.first_name}': context.first_name ?? '',
  '{member.last_name}': context.last_name ?? '',
  '{member.email_address}': context.to_email ?? '',
  '{member.membership}': context.membership ?? ''
};
const applyTokens = (value) => {
  let rendered = String(value ?? '');
  for (const [token, replacement] of Object.entries(tokenMap)) {
    rendered = rendered.split(token).join(String(replacement));
  }
  return rendered.trim();
};
const emailType = context.html_template && !context.text_template ? 'html' : 'text';
const bodySource = emailType === 'html' ? (context.html_template ?? context.text_template ?? '') : (context.text_template ?? context.html_template ?? '');
const signatureSource = emailType === 'html' ? (context.signature_html_template ?? context.signature_text_template ?? '') : (context.signature_text_template ?? context.signature_html_template ?? '');
const intendedRecipient = context.to_email;
const actualRecipient = input.delivery_mode === 'production' ? intendedRecipient : input.test_recipient;
return [{ json: { member_id: input.member_id, member: context.member_name, membership: context.membership, email: input.email || context.to_email, template_key: context.template_key, template_name: context.template_name || context.template_key, delivery_mode: input.delivery_mode, test_recipient: input.test_recipient, intended_recipient: intendedRecipient, actual_recipient: actualRecipient, return_url: input.return_url, sender_name: input.sender_name, reply_to: input.reply_to, rendered_subject: applyTokens(context.subject_template ?? 'Message from Avondale Tennis Club'), rendered_body: applyTokens(bodySource), rendered_signature: applyTokens(signatureSource), email_type: emailType, send_url: `${input.n8n_base_url}/webhook/send-member-template-email` } }];

const item = $('Render Preview Data').first().json ?? {};
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const bodyPreview = escapeHtml(item.rendered_body).replace(/\r?\n/g, '&#10;');
const signaturePreview = escapeHtml(item.rendered_signature).replace(/\r?\n/g, '&#10;');
const subjectPreview = escapeHtml(item.rendered_subject);
const modeChecked = item.delivery_mode !== 'production' ? ' checked' : '';
const modeLabel = item.delivery_mode === 'production' ? 'Production' : 'Test';
const recipientSummary = item.delivery_mode === 'production'
  ? escapeHtml(item.actual_recipient)
  : `${escapeHtml(item.actual_recipient)} (intended recipient: ${escapeHtml(item.intended_recipient)})`;
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Email Preview</title><style>:root{color-scheme:light;--bg:#f7f8fc;--panel:#ffffff;--ink:#2e3d4e;--muted:#6b7785;--line:#e2e8f0;--accent:#509ee3;--accent-dark:#2f80d8;--soft:#f2f7fd;--button-soft:#eef2f7}*{box-sizing:border-box}body{margin:0;padding:24px;background:linear-gradient(180deg,#fbfcfe 0%,var(--bg) 100%);font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:var(--ink)}.wrap{max-width:960px;margin:0 auto;display:grid;gap:20px}.panel{background:var(--panel);border:1px solid var(--line);border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}h1{margin:0 0 10px;font-size:32px;line-height:1.05;letter-spacing:-.02em}.meta{margin:0;color:var(--muted);line-height:1.5}.summary{display:grid;gap:14px;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));margin-top:20px}.summary-card{border:1px solid var(--line);border-radius:14px;padding:16px;background:var(--soft)}.summary-card h2{margin:0 0 8px;font-size:13px;text-transform:uppercase;letter-spacing:.08em;color:var(--muted)}.summary-card p{margin:0;font-size:17px;line-height:1.4}.email-form{display:grid;gap:16px;margin-top:18px}.email-form label{display:grid;gap:8px;font-weight:700}.email-form input[type=text],.email-form textarea{width:100%;border:1px solid var(--line);border-radius:12px;padding:12px 14px;font:inherit;background:#fff;color:var(--ink)}.email-form textarea{min-height:320px;resize:vertical;line-height:1.5}.signature-preview textarea{min-height:120px;background:#f8fafc}.checkbox-wrap{display:inline-flex;align-items:center;gap:10px;font-weight:600}.checkbox-wrap input{width:18px;height:18px}.actions{display:flex;gap:12px;flex-wrap:wrap;align-items:center}.button,.secondary{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;border:0;cursor:pointer;font:inherit}.button{background:linear-gradient(135deg,var(--accent) 0%,var(--accent-dark) 100%);color:#fff;box-shadow:0 10px 24px rgba(80,158,227,.22)}.secondary{background:var(--button-soft);color:var(--ink);border:1px solid var(--line)}</style></head><body><div class="wrap"><section class="panel"><h1>Email Preview</h1><p class="meta">Review and edit the rendered message below before sending it. The signature shown below is appended automatically during send.</p><div class="summary"><div class="summary-card"><h2>Member</h2><p>${escapeHtml(item.member)}</p></div><div class="summary-card"><h2>Template</h2><p>${escapeHtml(item.template_name)}</p></div><div class="summary-card"><h2>Mode</h2><p>${escapeHtml(modeLabel)}</p></div><div class="summary-card"><h2>Recipient</h2><p>${recipientSummary}</p></div></div><form class="email-form" method="POST" action="${escapeHtml(item.send_url)}"><input type="hidden" name="member_id" value="${escapeHtml(item.member_id)}"><input type="hidden" name="member" value="${escapeHtml(item.member)}"><input type="hidden" name="membership" value="${escapeHtml(item.membership)}"><input type="hidden" name="email" value="${escapeHtml(item.email)}"><input type="hidden" name="template_key" value="${escapeHtml(item.template_key)}"><input type="hidden" name="return_url" value="${escapeHtml(item.return_url)}"><input type="hidden" name="email_type" value="${escapeHtml(item.email_type)}"><input type="hidden" name="rendered_signature" value="${escapeHtml(item.rendered_signature)}"><label><span>Subject</span><input type="text" name="rendered_subject" value="${subjectPreview}" required></label><label><span>Message</span><textarea name="rendered_message" required>${bodyPreview}</textarea></label><label class="signature-preview"><span>Signature</span><textarea readonly>${signaturePreview}</textarea></label><label><span>Mode</span><span class="checkbox-wrap"><input type="checkbox" name="test_mode" value="1"${modeChecked}> Send in test mode</span></label><div class="actions"><button type="submit" class="button">Send Email</button><a class="secondary" href="${escapeHtml(item.return_url)}">Back to Member Detail</a></div></form></section></div></body></html>`;
return [{ json: { html } }];
